using Microsoft.JSInterop;
using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService : IAsyncDisposable
{
    private readonly LocalStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _dotNetRef;
    private Timer? _syncTimer;

    public SyncStatus Status { get; private set; } = new();
    public event Action? OnStatusChanged;

    public SyncService(LocalStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("connectivityInterop.registerOnlineHandler", _dotNetRef);
        Status.IsOnline = await _js.InvokeAsync<bool>("connectivityInterop.isOnline");
        await UpdatePendingCount();
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        Status.IsOnline = isOnline;
        OnStatusChanged?.Invoke();
        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (!Status.IsOnline || Status.IsSyncing) return;

        Status.IsSyncing = true;
        OnStatusChanged?.Invoke();

        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("/api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.IsSynced = true;
                        await _storage.SaveInspectionAsync(inspection);
                    }
                }
                catch
                {
                    break;
                }
            }
            Status.LastSyncAt = DateTime.UtcNow;
        }
        finally
        {
            Status.IsSyncing = false;
            await UpdatePendingCount();
            OnStatusChanged?.Invoke();
        }
    }

    private async Task UpdatePendingCount()
    {
        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            Status.PendingCount = unsynced.Count;
        }
        catch
        {
            // IndexedDB might not be ready yet
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_syncTimer != null)
        {
            await _syncTimer.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}
```

## Step 4: Create `SiteInspector.Client/wwwroot/js/indexedDb.js`

```javascript
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('isSynced', 'isSynced', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbInterop = {
    save: async function(storeName, data) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).put(JSON.parse(data));
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getAll: async function(storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).getAll();
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getById: async function(storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const request = tx.objectStore(storeName).get(id);
            request.onsuccess = () => resolve(request.result ? JSON.stringify(request.result) : null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    delete: async function(storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            tx.objectStore(storeName).delete(id);
            tx.oncomplete = () => resolve(true);
            tx.onerror = (e) => reject(e.target.error);
        });
    },

    getByIndex: async function(storeName, indexName, value) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const index = tx.objectStore(storeName).index(indexName);
            const request = index.getAll(value);
            request.onsuccess = () => resolve(JSON.stringify(request.result));
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getUnsyncedInspections: async function() {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction('inspections', 'readonly');
            const store = tx.objectStore('inspections');
            const request = store.getAll();
            request.onsuccess = () => {
                const unsynced = request.result.filter(i => !i.isSynced);
                resolve(JSON.stringify(unsynced));
            };
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

window.connectivityInterop = {
    isOnline: function() {
        return navigator.onLine;
    },
    registerOnlineHandler: function(dotNetRef) {
        window.addEventListener('online', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', true));
        window.addEventListener('offline', () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', false));
    }
};
