    --warning-color: #ff9800;
    --radius: 12px;
    --shadow: 0 4px 6px rgba(0,0,0,0.3);
}

* {
    box-sizing: border-box;
}

html, body {
    margin: 0;
    padding: 0;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background-color: var(--bg-dark);
    color: var(--text-primary);
    min-height: 100vh;
    -webkit-tap-highlight-color: transparent;
}

.page {
    padding: 1rem;
    padding-bottom: 5rem;
    max-width: 600px;
    margin: 0 auto;
}

/* Header */
.app-header {
    background: var(--bg-card);
    padding: 0.75rem 1rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
    border-bottom: 1px solid var(--bg-surface);
    position: sticky;
    top: 0;
    z-index: 100;
}

.app-header h1 {
    font-size: 1.1rem;
    margin: 0;
    font-weight: 600;
}

.sync-indicator {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    font-size: 0.8rem;
    color: var(--text-secondary);
}

.sync-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
    background: var(--pass-color);
}

.sync-dot.offline {
    background: var(--fail-color);
}

.sync-dot.syncing {
    background: var(--warning-color);
    animation: pulse 1s infinite;
}

@keyframes pulse {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.4; }
}

/* Bottom Navigation */
.bottom-nav {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: var(--bg-card);
    display: flex;
    justify-content: space-around;
    padding: 0.5rem 0;
    padding-bottom: max(0.5rem, env(safe-area-inset-bottom));
    border-top: 1px solid var(--bg-surface);
    z-index: 100;
}

.nav-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-decoration: none;
    color: var(--text-secondary);
    font-size: 0.7rem;
    padding: 0.25rem 0.75rem;
    border-radius: 8px;
    min-width: 60px;
    transition: color 0.2s;
}

.nav-item.active, .nav-item:hover {
    color: var(--primary);
}

.nav-item .nav-icon {
    font-size: 1.4rem;
    margin-bottom: 2px;
}

/* Cards */
.card {
    background: var(--bg-card);
    border-radius: var(--radius);
    padding: 1rem;
    margin-bottom: 0.75rem;
    box-shadow: var(--shadow);
    border: 1px solid var(--bg-surface);
}

.card h3 {
    margin: 0 0 0.25rem;
    font-size: 1rem;
}

.card p {
    margin: 0;
    color: var(--text-secondary);
    font-size: 0.85rem;
}

/* Buttons */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0.75rem 1.5rem;
    border: none;
    border-radius: var(--radius);
    font-size: 1rem;
    font-weight: 600;
    cursor: pointer;
    min-height: 48px;
    min-width: 48px;
    transition: transform 0.1s, opacity 0.2s;
    text-decoration: none;
}

.btn:active {
    transform: scale(0.95);
}

.btn-primary {
    background: var(--primary);
    color: white;
}

.btn-primary:hover {
    background: var(--primary-dark);
}

.btn-block {
    display: flex;
    width: 100%;
}

.btn-sm {
    padding: 0.5rem 1rem;
    font-size: 0.85rem;
    min-height: 40px;
}

/* Checklist */
.checklist-category {
    margin-bottom: 1.5rem;
}

.checklist-category h4 {
    color: var(--primary);
    font-size: 0.9rem;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    margin: 0 0 0.75rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid var(--bg-surface);
}

.checklist-item {
    background: var(--bg-card);
    border-radius: var(--radius);
    padding: 0.75rem;
    margin-bottom: 0.5rem;
    border: 1px solid var(--bg-surface);
}

.checklist-item-desc {
    font-size: 0.9rem;
    margin-bottom: 0.5rem;
}

.checklist-buttons {
    display: flex;
    gap: 0.5rem;
}

.checklist-btn {
    flex: 1;
    padding: 0.6rem;
    border: 2px solid transparent;
    border-radius: 8px;
    font-size: 0.8rem;
    font-weight: 700;
    cursor: pointer;
    min-height: 44px;
    transition: all 0.15s;
    background: var(--bg-surface);
    color: var(--text-secondary);
}

.checklist-btn:active {
    transform: scale(0.93);
}

.checklist-btn.pass {
    border-color: var(--pass-color);
    color: var(--pass-color);
}

.checklist-btn.pass.selected {
    background: var(--pass-bg);
    color: var(--pass-color);
    border-color: var(--pass-color);
}

.checklist-btn.fail {
    border-color: var(--fail-color);
    color: var(--fail-color);
}

.checklist-btn.fail.selected {
    background: var(--fail-bg);
    color: var(--fail-color);
    border-color: var(--fail-color);
}

.checklist-btn.na {
    border-color: var(--na-color);
    color: var(--na-color);
}

.checklist-btn.na.selected {
    background: var(--na-bg);
    color: var(--na-color);
    border-color: var(--na-color);
}

/* Form inputs */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    font-size: 0.85rem;
    color: var(--text-secondary);
    margin-bottom: 0.25rem;
}

.form-control {
    width: 100%;
    padding: 0.75rem;
    background: var(--bg-surface);
    border: 1px solid var(--bg-surface);
    border-radius: 8px;
    color: var(--text-primary);
    font-size: 1rem;
    min-height: 48px;
}

.form-control:focus {
    outline: none;
    border-color: var(--primary);
}

textarea.form-control {
    min-height: 80px;
    resize: vertical;
}

/* Status badges */
.badge {
    display: inline-block;
    padding: 0.25rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
}

.badge-pass { background: var(--pass-bg); color: var(--pass-color); }
.badge-fail { background: var(--fail-bg); color: var(--fail-color); }
.badge-pending { background: var(--na-bg); color: var(--warning-color); }
.badge-synced { background: var(--pass-bg); color: var(--pass-color); }

/* Photo grid */
.photo-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
    gap: 0.5rem;
    margin-top: 0.5rem;
}

.photo-thumb {
    aspect-ratio: 1;
    border-radius: 8px;
    overflow: hidden;
    background: var(--bg-surface);
}

.photo-thumb img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

/* Progress bar */
.progress-bar {
    height: 6px;
    background: var(--bg-surface);
    border-radius: 3px;
    overflow: hidden;
    margin: 0.5rem 0;
}

.progress-fill {
    height: 100%;
    background: var(--primary);
    border-radius: 3px;
    transition: width 0.3s;
}

/* Sync page */
.sync-status-card {
    text-align: center;
    padding: 2rem 1rem;
}

.sync-status-card .status-icon {
    font-size: 3rem;
    margin-bottom: 1rem;
}

/* Empty state */
.empty-state {
    text-align: center;
    padding: 3rem 1rem;
    color: var(--text-secondary);
}

.empty-state .icon {
    font-size: 3rem;
    margin-bottom: 1rem;
}

/* Notes toggle */
.notes-toggle {
    font-size: 0.8rem;
    color: var(--text-secondary);
    cursor: pointer;
    margin-top: 0.25rem;
    padding: 0.25rem;
}

.item-notes {
    margin-top: 0.5rem;
}

.item-notes input {
    width: 100%;
    padding: 0.5rem;
    background: var(--bg-surface);
    border: 1px solid var(--bg-surface);
    border-radius: 6px;
    color: var(--text-primary);
    font-size: 0.85rem;
}

.item-notes input:focus {
    outline: none;
    border-color: var(--primary);
}

/* Loading */
.loading {
    text-align: center;
    padding: 2rem;
    color: var(--text-secondary);
}
```

