using Microsoft.JSInterop;
using System.Net.Http.Json;
using SiteInspector.Client.Models;

namespace SiteInspector.Client.Services;

public class SyncService : IAsyncDisposable
{
    private readonly LocalStorageService _storage;
    private readonly HttpClient _http;
    private readonly IJSRuntime _js;
    private DotNetObjectReference<SyncService>? _dotNetRef;
    private Timer? _syncTimer;

    public SyncStatus Status { get; private set; } = new();
    public event Action? OnStatusChanged;

    public SyncService(LocalStorageService storage, HttpClient http, IJSRuntime js)
    {
        _storage = storage;
        _http = http;
        _js = js;
    }

    public async Task InitializeAsync()
    {
        _dotNetRef = DotNetObjectReference.Create(this);
        await _js.InvokeVoidAsync("connectivityInterop.registerOnlineHandler", _dotNetRef);
        Status.IsOnline = await _js.InvokeAsync<bool>("connectivityInterop.isOnline");
        await UpdatePendingCount();
        _syncTimer = new Timer(async _ => await TrySyncAsync(), null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
    }

    [JSInvokable]
    public async Task OnConnectivityChanged(bool isOnline)
    {
        Status.IsOnline = isOnline;
        OnStatusChanged?.Invoke();
        if (isOnline)
        {
            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (!Status.IsOnline || Status.IsSyncing) return;

        Status.IsSyncing = true;
        OnStatusChanged?.Invoke();

        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            foreach (var inspection in unsynced)
            {
                try
                {
                    var response = await _http.PostAsJsonAsync("/api/inspections", inspection);
                    if (response.IsSuccessStatusCode)
                    {
                        inspection.IsSynced = true;
                        await _storage.SaveInspectionAsync(inspection);
                    }
                }
                catch
                {
                    break;
                }
            }
            Status.LastSyncAt = DateTime.UtcNow;
        }
        finally
        {
            Status.IsSyncing = false;
            await UpdatePendingCount();
            OnStatusChanged?.Invoke();
        }
    }

    private async Task UpdatePendingCount()
    {
        try
        {
            var unsynced = await _storage.GetUnsyncedInspectionsAsync();
            Status.PendingCount = unsynced.Count;
        }
        catch
        {
            // IndexedDB might not be ready yet
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_syncTimer != null)
        {
            await _syncTimer.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

