@page "/"
@inject LocalStorageService Storage

<h2>Construction Sites</h2>

@if (_showAddForm)
{
    <div class="card">
        <div class="form-group">
            <label>Site Name</label>
            <input class="form-control" @bind="_newSiteName" placeholder="e.g., Tower Block A" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <input class="form-control" @bind="_newSiteAddress" placeholder="e.g., 123 Main St" />
        </div>
        <div style="display:flex; gap:0.5rem;">
            <button class="btn btn-primary btn-sm" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Add Site</button>
            <button class="btn btn-sm" style="background:var(--bg-surface);color:var(--text-secondary);" @onclick="() => _showAddForm = false">Cancel</button>
        </div>
    </div>
}
else
{
    <button class="btn btn-primary btn-block" @onclick="() => _showAddForm = true">+ Add New Site</button>
}

<div style="margin-top:1rem;">
    @if (_sites == null)
    {
        <div class="loading">Loading sites...</div>
    }
    else if (_sites.Count == 0)
    {
        <div class="empty-state">
            <div class="icon">🏗️</div>
            <p>No sites yet. Add your first construction site above.</p>
        </div>
    }
    else
    {
        @foreach (var site in _sites)
        {
            <div class="card">
                <h3>@site.Name</h3>
                <p>@site.Address</p>
                <div style="margin-top:0.75rem;">
                    <a class="btn btn-primary btn-sm" href="@($"inspect/{site.Id}")">▶ Start Inspection</a>
                </div>
            </div>
        }
    }
</div>

@code {
    private List<InspectionSite>? _sites;
    private bool _showAddForm;
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _sites = await Storage.GetAllSitesAsync();
            StateHasChanged();
        }
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;

        var site = new InspectionSite
        {
            Name = _newSiteName.Trim(),
            Address = _newSiteAddress.Trim()
        };

        await Storage.SaveSiteAsync(site);
        _sites ??= new();
        _sites.Add(site);
        _newSiteName = "";
        _newSiteAddress = "";
        _showAddForm = false;
    }
}

@page "/inspect/{SiteId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<h2>New Inspection</h2>

@if (_inspection == null)
{
    <div class="loading">Preparing checklist...</div>
}
else
{
    <div class="card">
        <div class="form-group">
            <label>Inspector Name</label>
            <input class="form-control" @bind="_inspection.InspectorName" placeholder="Your name" />
        </div>
    </div>

    <div class="progress-bar">
        <div class="progress-fill" style="width: @(GetProgress())%"></div>
    </div>
    <p style="font-size:0.8rem; color:var(--text-secondary); margin-bottom:1rem;">
        @GetCompletedCount() / @_inspection.ChecklistItems.Count items inspected
    </p>

    @foreach (var group in _inspection.ChecklistItems.GroupBy(i => i.Category))
    {
        <div class="checklist-category">
            <h4>@group.Key</h4>
            @foreach (var item in group)
            {
                <div class="checklist-item">
                    <div class="checklist-item-desc">@item.Description</div>
                    <div class="checklist-buttons">
                        <button class="checklist-btn pass @(item.Result == ChecklistResult.Pass ? "selected" : "")"
                                @onclick="() => SetResult(item, ChecklistResult.Pass)">✓ Pass</button>
                        <button class="checklist-btn fail @(item.Result == ChecklistResult.Fail ? "selected" : "")"
                                @onclick="() => SetResult(item, ChecklistResult.Fail)">✗ Fail</button>
                        <button class="checklist-btn na @(item.Result == ChecklistResult.NotApplicable ? "selected" : "")"
                                @onclick="() => SetResult(item, ChecklistResult.NotApplicable)">N/A</button>
                    </div>
                    @if (_expandedNotes.Contains(item.Id))
                    {
                        <div class="item-notes">
                            <input @bind="item.Notes" @bind:event="oninput" placeholder="Add note..." />
                        </div>
                    }
                    <div class="notes-toggle" @onclick="() => ToggleNotes(item.Id)">
                        @(string.IsNullOrEmpty(item.Notes) ? "+ Add note" : "📝 " + item.Notes)
                    </div>
                </div>
            }
        </div>
    }

    <PhotoCapture Photos="_inspection.Photos" OnPhotosChanged="SaveProgress" />

    <div class="form-group">
        <label>General Notes</label>
        <textarea class="form-control" @bind="_inspection.Notes" placeholder="Overall observations..."></textarea>
    </div>

    <div style="display:flex; gap:0.5rem; margin-top:1rem; margin-bottom:2rem;">
        <button class="btn btn-primary btn-block" @onclick="CompleteInspection">✓ Complete Inspection</button>
    </div>
    <div>
        <button class="btn btn-block btn-sm" style="background:var(--bg-surface);color:var(--text-secondary);" @onclick="SaveAndExit">Save & Exit</button>
    </div>
}

@code {
    [Parameter] public string SiteId { get; set; } = "";

    private Inspection? _inspection;
    private HashSet<string> _expandedNotes = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            var sites = await Storage.GetAllSitesAsync();
            var site = sites.FirstOrDefault(s => s.Id == SiteId);

            _inspection = new Inspection
            {
                SiteId = SiteId,
                SiteName = site?.Name ?? "Unknown Site",
                ChecklistItems = ChecklistTemplates.GetDefaultSafetyChecklist()
            };
            StateHasChanged();
        }
    }

    private void SetResult(ChecklistItem item, ChecklistResult result)
    {
        item.Result = result;
    }

    private void ToggleNotes(string itemId)
    {
        if (!_expandedNotes.Add(itemId))
            _expandedNotes.Remove(itemId);
    }

    private int GetCompletedCount() =>
        _inspection?.ChecklistItems.Count(i => i.Result != ChecklistResult.NotInspected) ?? 0;

    private double GetProgress()
    {
        if (_inspection == null || _inspection.ChecklistItems.Count == 0) return 0;
        return (double)GetCompletedCount() / _inspection.ChecklistItems.Count * 100;
    }

    private async Task SaveProgress()
    {
        if (_inspection != null)
            await Storage.SaveInspectionAsync(_inspection);
    }

    private async Task CompleteInspection()
    {
        if (_inspection == null) return;
        _inspection.Status = InspectionStatus.Completed;
        await Storage.SaveInspectionAsync(_inspection);
        Nav.NavigateTo("/history");
    }

    private async Task SaveAndExit()
    {
        if (_inspection != null)
            await Storage.SaveInspectionAsync(_inspection);
        Nav.NavigateTo("/");
    }
}

