+                    </div>
+                    <div>
+                        @if (inspection.Status == InspectionStatus.Completed)
+                        {
+                            <span class="badge badge-pass">Completed</span>
+                        }
+                        else
+                        {
+                            <span class="badge badge-pending">In Progress</span>
+                        }
+                    </div>
+                </div>
+                <div style="margin-top:0.5rem; display:flex; gap:0.5rem; align-items:center;">
+                    @{ var passed = inspection.ChecklistItems.Count(i => i.Result == ChecklistResult.Pass); }
+                    @{ var failed = inspection.ChecklistItems.Count(i => i.Result == ChecklistResult.Fail); }
+                    @{ var total = inspection.ChecklistItems.Count; }
+                    <span style="font-size:0.8rem; color:var(--pass-color);">✓ @passed</span>
+                    <span style="font-size:0.8rem; color:var(--fail-color);">✗ @failed</span>
+                    <span style="font-size:0.8rem; color:var(--text-secondary);">/ @total items</span>
+                    @if (!inspection.IsSynced)
+                    {
+                        <span class="badge badge-pending" style="margin-left:auto;">Not synced</span>
+                    }
+                    else
+                    {
+                        <span class="badge badge-synced" style="margin-left:auto;">Synced</span>
+                    }
+                </div>
+                @if (inspection.Status == InspectionStatus.InProgress)
+                {
+                    <div style="margin-top:0.75rem;">
+                        <a class="btn btn-primary btn-sm" href="@($"inspection/{inspection.Id}")">Continue</a>
+                    </div>
+                }
