+@page "/sync"
+@inject SyncService SyncService
+@implements IDisposable
+
+<h2>Sync Status</h2>
+
+<div class="card sync-status-card">
+    <div class="status-icon">
+        @if (SyncService.Status.IsSyncing)
+        {
+            <span>🔄</span>
+        }
+        else if (SyncService.Status.IsOnline)
+        {
+            <span>✅</span>
+        }
+        else
+        {
+            <span>📡</span>
+        }
+    </div>
+
+    <h3>
+        @if (SyncService.Status.IsSyncing)
+        {
+            <text>Syncing...</text>
+        }
+        else if (SyncService.Status.IsOnline)
+        {
+            <text>Online</text>
+        }
+        else
+        {
+            <text>Offline</text>
+        }
+    </h3>
+
+    <p style="color:var(--text-secondary); margin-top:0.5rem;">
+        @if (SyncService.Status.PendingCount > 0)
+        {
+            <text>@SyncService.Status.PendingCount inspection(s) waiting to sync</text>
+        }
+        else
+        {
+            <text>All inspections synced</text>
+        }
+    </p>
+
+    @if (SyncService.Status.LastSyncAt.HasValue)
+    {
+        <p style="font-size:0.8rem; color:var(--text-secondary); margin-top:0.25rem;">
+            Last sync: @SyncService.Status.LastSyncAt.Value.ToLocalTime().ToString("g")
+        </p>
+    }
+</div>
+
+<button class="btn btn-primary btn-block" @onclick="ManualSync"
+        disabled="@(!SyncService.Status.IsOnline || SyncService.Status.IsSyncing)">
+    @(SyncService.Status.IsSyncing ? "Syncing..." : "Sync Now")
+</button>
+
+<div class="card" style="margin-top:1rem;">
+    <h3 style="font-size:0.9rem;">How Sync Works</h3>
+    <p style="font-size:0.85rem;">
+        Inspections are saved locally on your device. When you're online, they automatically sync to the server every 30 seconds.
+        You can also tap "Sync Now" to sync immediately.
+    </p>
+</div>
+
+@code {
+    protected override void OnInitialized()
+    {
+        SyncService.OnStatusChanged += HandleStatusChanged;
+    }
+
+    private async Task ManualSync()
+    {
+        await SyncService.TrySyncAsync();
+    }
+
+    private void HandleStatusChanged()
+    {
+        InvokeAsync(StateHasChanged);
+    }
+
+    public void Dispose()
+    {
+        SyncService.OnStatusChanged -= HandleStatusChanged;
+    }
+}
+

