+    <h4 style="font-size:0.9rem; color:var(--text-secondary); margin-bottom:0.5rem;">📷 Photos</h4>
+
+    <label class="btn btn-sm" style="background:var(--bg-surface); color:var(--text-primary); cursor:pointer;">
+        + Add Photo
+        <InputFile accept="image/*" capture="environment" OnChange="OnFileSelected" style="display:none;" />
+    </label>
+
+    @if (Photos.Count > 0)
+    {
+        <div class="photo-grid">
