@inherits LayoutComponentBase
@inject SyncService SyncService
@implements IDisposable

<div class="app-layout">
    <header class="app-header">
        <h1>🏗️ Site Inspector</h1>
        <div class="sync-indicator">
            <span>@(SyncService.Status.PendingCount > 0 ? $"{SyncService.Status.PendingCount} pending" : "")</span>
            <div class="sync-dot @GetSyncClass()"></div>
        </div>
    </header>

    <main class="page">
        @Body
    </main>

    <nav class="bottom-nav">
        <NavLink class="nav-item" href="" Match="NavLinkMatch.All">
            <span class="nav-icon">🏢</span>
            <span>Sites</span>
        </NavLink>
        <NavLink class="nav-item" href="history">
            <span class="nav-icon">📋</span>
            <span>History</span>
        </NavLink>
        <NavLink class="nav-item" href="sync">
            <span class="nav-icon">🔄</span>
            <span>Sync</span>
        </NavLink>
    </nav>
</div>

@code {
    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            SyncService.OnStatusChanged += HandleStatusChanged;
            await SyncService.InitializeAsync();
            StateHasChanged();
        }
    }

    private void HandleStatusChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private string GetSyncClass()
    {
        if (SyncService.Status.IsSyncing) return "syncing";
        if (!SyncService.Status.IsOnline) return "offline";
        return "";
    }

    public void Dispose()
    {
        SyncService.OnStatusChanged -= HandleStatusChanged;
    }
}
EOF

